```class Solution {
public:
    int minStartingIndex(string s, string pattern) {
        int n = s.size(), m = pattern.size(), res = -1, cnt = 0;
        for (int i = 0; i <= n - m; ++i) {
            cnt = 0;
            for (int j = 0; j < m; ++j) {
                if (s[i + j] != pattern[j]) ++cnt;
                if (cnt > 1) break;
            }
            if (cnt <= 1) res = i;
        }
        return res;
    }
};
```
